    lfoDepth.connect(oscA.detune);
    lfoDepth.connect(oscB.detune);
    oscA.connect(mix);
    oscB.connect(mix);
    sub.connect(subGain);
    subGain.connect(mix);
    mix.connect(filter);
    filter.connect(amp);
    amp.connect(pan);
    pan.connect(master);

