const baseUrl = process.env.JAM_BASE_URL || 'http://localhost:3000';

function usage() {
  console.error(`Usage:
  npm run jam -- state
  npm run jam -- elements
  npm run jam -- add '{"id":"elem_x","filePath":"/elements/elem_x_visual.js","type":"visual","authored":"hand"}'
  npm run jam -- patch <id> '{"authored":"hand"}'
